```python
import requests
import json
import pandas as pd
import matplotlib.pyplot as plt
from time import sleep
from Bio import SeqIO
from urllib.parse import quote

# Define constants
RCSB_API_URL = "https://data.rcsb.org/graphql"
RCSB_API_QUERY = """
    query {
        search(query: "*") {
            total
            resultSets {
                resultSet {
                    entries {
                        pdb_id
                        title
                        experimental_method
                        resolution
                        deposition_date
                        chains {
                            chain_id
                            uniprot_ids
                        }
                    }
                }
            }
        }
    }
"""
RCSB_API_QUERY_FILTER = """
    query {
        search(query: "organism_scientific_name:SARS-CoV-2") {
            total
            resultSets {
                resultSet {
                    entries {
                        pdb_id
                        title
                        experimental_method
                        resolution
                        deposition_date
                        chains {
                            chain_id
                            uniprot_ids
                        }
                    }
                }
            }
        }
    }
"""
GENE_MAP = {
    "Spike": ["P0DTC2"],
    "NSP1": ["P0DTD1"],
    "NSP2": ["P0DTD2"],
    "NSP3": ["P0DTD3"],
    "NSP4": ["P0DTD4"],
    "NSP5": ["P0DTD5"],
    "NSP6": ["P0DTD6"],
    "NSP7": ["P0DTD7"],
    "NSP8": ["P0DTD8"],
    "NSP9": ["P0DTD9"],
    "NSP10": ["P0DTE0"],
    "NSP11": ["P0DTE1"],
    "NSP12": ["P0DTE2"],
    "NSP13": ["P0DTE3"],
    "NSP14": ["P0DTE4"],
    "NSP15": ["P0DTE5"],
    "NSP16": ["P0DTE6"],
    "N": ["P0DTC9"],
    "E": ["P0DTC4"],
    "M": ["P0DTC5"]
}

def query_rcsb_api(query):
    headers = {"Content-Type": "application/json"}
    response = requests.post(RCSB_API_URL, headers=headers, data=json.dumps({"query": query}))
    return response.json()

def extract_structure_metadata(structure):
    metadata = {
        "pdb_id": structure["pdb_id"],
        "resolution": structure["resolution"],
        "structure_method": structure["experimental_method"],
        "deposited_chain_ids": [chain["chain_id"] for chain in structure["chains"]],
        "uniprot_accessions": [chain["uniprot_ids"] for chain in structure["chains"]]
    }
    return metadata

def map_chains_to_genes(structure_metadata):
    gene_map = {}
    for chain in structure_metadata["deposited_chain_ids"]:
        for gene, uniprot_ids in GENE_MAP.items():
            if structure_metadata["uniprot_accessions"]:
                for uniprot_id in structure_metadata["uniprot_accessions"]:
                    if uniprot_id in uniprot_ids:
                        if gene not in gene_map:
                            gene_map[gene] = []
                        gene_map[gene].append(chain)
    return gene_map

def produce_coverage_table(structure_metadata_list):
    coverage_table = {}
    for structure_metadata in structure_metadata_list:
        gene_map = map_chains_to_genes(structure_metadata)
        for gene, chains in gene_map.items():
            if gene not in coverage_table:
                coverage_table[gene] = {"count": 0, "resolutions": []}
            coverage_table[gene]["count"] += 1
            coverage_table[gene]["resolutions"].append(structure_metadata["resolution"])
    for gene, data in coverage_table.items():
        coverage_table[gene]["mean_resolution"] = sum(data["resolutions"]) / len(data["resolutions"])
    return coverage_table

def plot_coverage_table(coverage_table):
    genes = list(coverage_table.keys())
    counts = [data["count"] for data in coverage_table.values()]
    plt.bar(genes, counts)
    plt.xlabel("Gene")
    plt.ylabel("Number of Structures")
    plt.title("Structure Coverage per Gene")
    plt.show()

def main():
    # Query RCSB API for structures with 'SARS-CoV-2' organism annotation
    response = query_rcsb_api(RCSB_API_QUERY_FILTER)
    structure_list = response["data"]["search"]["resultSets"][0]["resultSet"]["entries"]

    # Extract structure metadata
    structure_metadata_list = [extract_structure_metadata(structure) for structure in structure_list]

    # Produce coverage table
    coverage_table = produce_coverage_table(structure_metadata_list)

    # Print coverage table
    print("Coverage Table:")
    for gene, data in coverage_table.items():
        print(f"{gene}: {data['count']} structures, mean resolution: {data['mean_resolution']}")

    # Plot coverage table
    plot_coverage_table(coverage_table)

if __name__ == "__main__":
    main()
```

**Note:**

1.  The above code uses the `requests` library to make API calls to the RCSB PDB REST API.
2.  The `query_rcsb_api` function sends a GraphQL query to the RCSB API and returns the response as a JSON object.
3.  The `extract_structure_metadata` function extracts relevant metadata from a structure, including PDB ID, resolution, structure method, deposited chain IDs, and UniProt accession.
4.  The `map_chains_to_genes` function maps chains to SARS-CoV-2 proteome genes based on UniProt accession.
5.  The `produce_coverage_table` function produces a coverage table showing the number of structures per gene and the mean resolution per gene.
6.  The `plot_coverage_table` function plots a bar chart of structure coverage per gene using `matplotlib`.
7.  The `main` function queries the RCSB API, extracts structure metadata, produces the coverage table, prints the coverage table, and plots the coverage table.

**Rate Limiting:**

To respect the RCSB API guidelines, you should implement rate limiting in your code. The RCSB API allows 50 requests per minute from the same IP address. You can use the `time.sleep` function to introduce a delay between requests.

```python
import time

# ...

def query_rcsb_api(query):
    # ...
    time.sleep(1.2)  # Introduce a 1.2-second delay between requests
    return response.json()

# ...
```

**Error Handling:**

You should also implement error handling in your code to handle potential errors that may occur during API calls or data processing. You can use `try-except` blocks to catch and handle exceptions.

```python
import requests

# ...

def query_rcsb_api(query):
    try:
        response = requests.post(RCSB_API_URL, headers=headers, data=json.dumps({"query": query}))
        response.raise_for_status()
        return response.json()
    except requests.exceptions.RequestException as e:
        print(f"Error: {e}")
        return None

# ...
